/**
 * 战斗风格世界书开关（仅控制“战斗风格”条目）
 *
 * 逻辑：
 * - 当 `主角.状态` 归一化后为 `战斗` 时：
 *   - 读取 `主角.战斗风格`（如 `剑圣风格1` / `骗术师风格2` ...）
 *   - 对所有世界书条目中包含 `风格1~4` 的条目：
 *     - 若条目名称包含当前 `主角.战斗风格` 字符串 => `enabled=true`
 *     - 否则 => `enabled=false`
 * - 当 `主角.状态` 不是战斗时，所有风格条目 => `enabled=false`
 *
 * 追加功能（不影响原有战斗风格逻辑）：
 * - 读取 `世界.当前位置`（兜底 `世界.当前地点`；兼容 `stat_data` / `mvu` 等常见 MVU 嵌套）
 * - 对“地点条目白名单”中对应名称的条目：
 *   - 当前地点匹配时 `enabled=true`
 *   - 当前地点非匹配时 `enabled=false`
 * - 「柳木镇·尼斯温泉」**并联**一路（不改变上面白名单条目的逻辑）：
 *   - 仍按原规则：`matchesLocationEntry(条目名, 当前位置)` 为真 → 开启；
 *   - **另加**：当前位置含「柳木镇」且（输入框或近期正文）含「温泉」→ 也可开启；
 *   - 两路任一为真即 `enabled=true`，否则 `false`。
 */

const SCAN_DEBOUNCE_MS = 250;
const HERO_POLL_MS = 900;

/** 尼斯温泉：须身处该镇任意子区域 */
const LIUYU_TOWN_MARKER = '柳木镇';
/** 世界书条目名须包含此片段 */
const NI_SI_ONSEN_ENTRY_MARKER = '柳木镇·尼斯温泉';
const ONSEN_KEYWORD = '温泉';
/** 扫描近期楼层正文是否出现关键字（与输入框并列） */
const ONSEN_CHAT_SCAN_LAST = 24;
/** 丽亚娜条目：柳木镇温泉并联开关 */
const LIYANA_ENTRY_MARKER = '丽亚娜·恩维尔';
/** 输入框触发后持续两楼：以 getLastMessageId() 为锚 */
const LIYANA_STICKY_FLOOR_DELTA = 2;

const TEXTAREA_SELECTORS =
  '#send_textarea, textarea[name="send_textarea"], textarea#send_textarea, #send_text, textarea[data-testid="send_textarea"], textarea.mes_textarea';

const STATUS_KEY = '状态';
const STYLE_KEY = '战斗风格';

// 需要自动开/关的“地点条目”名称白名单（必须与世界书条目 name 完全相等，见 isLocationEntryName）
// 例：当前 `世界.当前位置` = '午夜玫瑰' 时，会开启条目 '午夜玫瑰'
// 「柳木镇·尼斯温泉」也在白名单内便于对照；实际在循环里单独处理（原位置匹配 || 并联温泉关键字）
const LOCATION_ENTRY_NAMES = [
  '暗月城·午夜玫瑰',
  '柳木镇·住宅区',
  '柳木镇·尼斯温泉',
  '界域·阴影森林',
];

function readLocationFromAnyShape(candidate: any): unknown {
  // 与 readHeroValueFromAnyShape 一致：MVU / Dark 等常把数据放在 stat_data（或嵌套 stat_data）下
  return (
    candidate?.stat_data?.世界?.当前位置 ??
    candidate?.stat_data?.世界?.当前地点 ??
    candidate?.stat_data?.stat_data?.世界?.当前位置 ??
    candidate?.stat_data?.stat_data?.世界?.当前地点 ??
    candidate?.世界?.当前位置 ??
    candidate?.世界?.当前地点 ??
    candidate?.mvu?.世界?.当前位置 ??
    candidate?.mvu?.世界?.当前地点
  );
}

function getWorldLocationValue(): string {
  const g = globalThis as any;

  try {
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const byLatest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' }) ?? {};
      const v = readLocationFromAnyShape(byLatest);
      if (v !== undefined && v !== null) return String(v).trim();
    }
  } catch {
    /* ignore */
  }

  const scopes: Array<{ type: Parameters<typeof getVariables>[0]['type']; message_id?: number | string }> = [
    { type: 'message', message_id: 'latest' },
    { type: 'chat' },
    { type: 'character' },
    { type: 'global' },
  ];

  for (const scope of scopes) {
    try {
      const v = getVariables(scope as any) as any;
      const got = readLocationFromAnyShape(v);
      if (got !== undefined && got !== null) return String(got).trim();
    } catch {
      /* ignore */
    }
  }

  return '';
}

function matchesLocationEntry(entryName: string, worldLocation: string): boolean {
  if (!entryName || !worldLocation) return false;
  if (entryName === worldLocation) return true;

  // 允许“当前位置写成包含/更长版本”，例如当前位置是“午夜玫瑰酒馆”，条目名是“午夜玫瑰”
  return worldLocation.includes(entryName) || entryName.includes(worldLocation);
}

function isLocationEntryName(entryName: string): boolean {
  // 含「柳木镇·尼斯温泉」的条目走并联分支，不在此用纯 matchesLocationEntry 单独处理
  if (entryName.includes(NI_SI_ONSEN_ENTRY_MARKER)) return false;
  return LOCATION_ENTRY_NAMES.includes(entryName);
}

function readTopSendTextareaText(): string {
  const readFromDoc = (doc: Document | undefined | null): string => {
    if (!doc) return '';
    const el = doc.querySelector(TEXTAREA_SELECTORS) as HTMLTextAreaElement | null;
    if (!el) return '';
    return String(el.value ?? '');
  };

  // 优先顶层（正常情况下发送框在 top）
  try {
    const topText = readFromDoc(window.top?.document);
    if (topText) return topText;
  } catch {
    /* ignore */
  }

  // 兜底：有些环境下脚本 iframe 无法读 top.document，改读自身 document
  try {
    return readFromDoc(document);
  } catch {
    return '';
  }
}

function stripScanText(raw: string): string {
  let s = raw;
  s = s.replace(/```[\s\S]*?```/g, ' ');
  s = s.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/gi, ' ');
  return s;
}

function recentChatContainsSubstring(sub: string): boolean {
  if (!sub) return false;
  try {
    const lastId = getLastMessageId();
    if (lastId < 0) return false;
    const msgs = getChatMessages(`0-${lastId}`);
    const slice = msgs.slice(Math.max(0, msgs.length - ONSEN_CHAT_SCAN_LAST));
    for (const m of slice) {
      const t = stripScanText(m.message ?? '');
      if (t.includes(sub)) return true;
    }
  } catch {
    /* ignore */
  }
  return false;
}

/** 当前位置在柳木镇任意子区域 */
function isInLiuyuTownArea(worldLocation: string): boolean {
  return Boolean(worldLocation && worldLocation.includes(LIUYU_TOWN_MARKER));
}

/** 并联支路：镇内任意子区域 + 输入框/正文含「温泉」（与 matchesLocationEntry 互不替代） */
function niSiOnsenParallelBranch(
  worldLocation: string,
  draftHasKeyword: boolean,
  chatHasKeyword: boolean,
): boolean {
  if (!isInLiuyuTownArea(worldLocation)) return false;
  return draftHasKeyword || chatHasKeyword;
}

function getLastMessageIdSafe(): number {
  try {
    return getLastMessageId();
  } catch {
    return -1;
  }
}

/** 无楼层时返回 0，避免首条消息发送后立刻失效 */
function anchorMessageIdForSticky(): number {
  const m = getLastMessageIdSafe();
  return m >= 0 ? m : 0;
}

function stickyAfterDraftOff(anchor: number, delta: number): { on: boolean; anchor: number } {
  const mid = getLastMessageIdSafe();
  if (anchor < 0) return { on: false, anchor: -1 };
  if (mid < 0) return { on: true, anchor };
  if (mid < anchor + Math.max(1, delta)) return { on: true, anchor };
  return { on: false, anchor: -1 };
}

function normalizeHeroStatusForCombat(raw: unknown): string {
  if (typeof raw !== 'string') return '';
  const t = raw.trim();
  if (!t) return '';

  // 兼容过渡态：`生活->战斗 (json_patch)` 取最后一段 `战斗`，并去掉尾部括号注释
  const lastSeg = t.includes('->') || t.includes('→') || t.includes('=>') || t.includes('/') ? t.split(/(?:->|→|=>|\/)/).pop() ?? t : t;
  return lastSeg.replace(/\s*\([^)]*\)\s*$/g, '').trim();
}

function readHeroValueFromAnyShape(candidate: any, key: string): unknown {
  // 常见层级：stat_data.主角[key] 或 stat_data.stat_data.主角[key] 或 顶层.主角[key]
  return (
    candidate?.stat_data?.主角?.[key] ??
    candidate?.stat_data?.stat_data?.主角?.[key] ??
    candidate?.主角?.[key] ??
    candidate?.mvu?.主角?.[key]
  );
}

function getHeroValue(key: string): unknown {
  const g = globalThis as any;

  try {
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const byLatest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' }) ?? {};
      const v = readHeroValueFromAnyShape(byLatest, key);
      if (v !== undefined) return v;
    }
  } catch {
    /* ignore */
  }

  // 兜底：从变量层读取（全局脚本 iframe 下也可用）
  const scopes: Array<{ type: Parameters<typeof getVariables>[0]['type']; message_id?: number | string }> = [
    { type: 'message', message_id: 'latest' },
    { type: 'chat' },
    { type: 'character' },
    { type: 'global' },
  ];

  for (const scope of scopes) {
    try {
      const v = getVariables(scope as any) as any;
      const got = readHeroValueFromAnyShape(v, key);
      if (got !== undefined) return got;
    } catch {
      /* ignore */
    }
  }

  return undefined;
}

function getPrimaryWorldbookName(): string | null {
  try {
    const { primary } = getCharWorldbookNames('current');
    const n = primary?.trim();
    return n ? n : null;
  } catch {
    return null;
  }
}

function isBattleStyleEntryName(entryName: string): boolean {
  // 只认“风格1~4”这类条目
  // 例如：剑圣风格1、骗术师风格2...
  return /风格[1-4]/.test(entryName);
}

function computeDesiredEnabled(entryName: string, heroInBattle: boolean, currentStyleLabel: string): boolean {
  if (!heroInBattle) return false;
  if (!currentStyleLabel) return false;
  return entryName.includes(currentStyleLabel);
}

let debounceTimer: ReturnType<typeof setTimeout> | null = null;
let lastHeroSnapshot = '';
let liyanaStickyAnchor = -1;

function bindTopSendTextareaForOnsen(): void {
  try {
    const doc = window.top?.document;
    if (!doc) return;
    const textarea = doc.querySelector(TEXTAREA_SELECTORS) as HTMLTextAreaElement | null;
    if (!textarea) return;
    const mark = '__battleStyleOnsenTa__';
    if ((textarea as any)[mark]) return;
    (textarea as any)[mark] = true;
    const tick = () => scheduleSync();
    textarea.addEventListener('input', tick);
    textarea.addEventListener('paste', tick);
    textarea.addEventListener('cut', tick);
  } catch {
    /* ignore */
  }
}

function scheduleSync(): void {
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    debounceTimer = null;
    void errorCatched(syncWorldbookBattleStyle)();
  }, SCAN_DEBOUNCE_MS);
}

async function syncWorldbookBattleStyle(): Promise<void> {
  const wbName = getPrimaryWorldbookName();
  if (!wbName) return;

  const heroStatusRaw = getHeroValue(STATUS_KEY);
  const heroStatusNormalized = normalizeHeroStatusForCombat(heroStatusRaw);
  const heroInBattle = heroStatusNormalized === '战斗';

  const currentStyleLabel = String(getHeroValue(STYLE_KEY) ?? '').trim();

  const currentWorldLocation = getWorldLocationValue();

  const draftHasOnsen = readTopSendTextareaText().includes(ONSEN_KEYWORD);
  const chatHasOnsen = recentChatContainsSubstring(ONSEN_KEYWORD);
  // 当前位置可能是更长描述（如含后缀），用 includes 更稳
  const liyanaExactOnsen = Boolean(currentWorldLocation && currentWorldLocation.includes(NI_SI_ONSEN_ENTRY_MARKER));
  const liyanaTownDraftHit = isInLiuyuTownArea(currentWorldLocation) && (draftHasOnsen || chatHasOnsen);
  let liyanaTownStickyOn: boolean;
  if (liyanaTownDraftHit) {
    liyanaStickyAnchor = anchorMessageIdForSticky();
    liyanaTownStickyOn = true;
  } else {
    const st = stickyAfterDraftOff(liyanaStickyAnchor, LIYANA_STICKY_FLOOR_DELTA);
    liyanaStickyAnchor = st.anchor;
    liyanaTownStickyOn = st.on;
  }
  const liyanaEnabledDesired = liyanaExactOnsen || liyanaTownStickyOn;

  if (liyanaEnabledDesired) {
    // 轻量调试：仅在需要开启时打印一次快照，方便排查“为何没开”
    console.info('[BattleStyleWorldbookToggle][丽亚娜]', {
      wbName,
      currentWorldLocation,
      liyanaExactOnsen,
      liyanaTownDraftHit,
      liyanaStickyAnchor,
      liyanaTownStickyOn,
    });
  }

  const snapshot = `${heroInBattle}|${currentStyleLabel}|${currentWorldLocation}|${draftHasOnsen}|${chatHasOnsen}|${liyanaEnabledDesired}|${liyanaStickyAnchor}`;
  if (snapshot === lastHeroSnapshot) return;
  lastHeroSnapshot = snapshot;

  await updateWorldbookWith(wbName, entries => {
    let changed = 0;

    for (const entry of entries) {
      const name = entry?.name ?? '';
      if (!name) continue;

      // 新增：丽亚娜·恩维尔（并联：1) 柳木镇前缀 + 输入框含温泉，且持续两楼；2) 当前位置=柳木镇·尼斯温泉）
      if (name.includes(LIYANA_ENTRY_MARKER)) {
        const nextEnabled = liyanaEnabledDesired;
        if (entry.enabled !== nextEnabled) {
          entry.enabled = nextEnabled;
          changed++;
        }
        continue;
      }

      // 原功能：战斗风格
      if (isBattleStyleEntryName(name)) {
        const nextEnabled = computeDesiredEnabled(name, heroInBattle, currentStyleLabel);
        if (entry.enabled !== nextEnabled) {
          entry.enabled = nextEnabled;
          changed++;
        }
        continue;
      }

      // 柳木镇·尼斯温泉：并联 = 原「当前位置↔条目名」逻辑 OR 镇内+温泉关键字
      if (name.includes(NI_SI_ONSEN_ENTRY_MARKER)) {
        const byLocation = matchesLocationEntry(name, currentWorldLocation);
        const byOnsen = niSiOnsenParallelBranch(
          currentWorldLocation,
          draftHasOnsen,
          chatHasOnsen,
        );
        const nextEnabled = byLocation || byOnsen;
        if (entry.enabled !== nextEnabled) {
          entry.enabled = nextEnabled;
          changed++;
        }
        continue;
      }

      // 追加功能：当前位置对应地点条目
      if (isLocationEntryName(name)) {
        const nextEnabled = matchesLocationEntry(name, currentWorldLocation);
        if (entry.enabled !== nextEnabled) {
          entry.enabled = nextEnabled;
          changed++;
        }
      }
    }

    return entries;
  });
}

function startHeroPoll(): void {
  let timer: ReturnType<typeof setInterval> | null = null;
  timer = setInterval(() => {
    const heroStatusRaw = getHeroValue(STATUS_KEY);
    const heroStatusNormalized = normalizeHeroStatusForCombat(heroStatusRaw);
    const heroInBattle = heroStatusNormalized === '战斗';
    const currentStyleLabel = String(getHeroValue(STYLE_KEY) ?? '').trim();
    const currentWorldLocation = getWorldLocationValue();
    const draftHasOnsen = readTopSendTextareaText().includes(ONSEN_KEYWORD);
    const chatHasOnsen = recentChatContainsSubstring(ONSEN_KEYWORD);
    const liyanaExactOnsen = Boolean(currentWorldLocation && currentWorldLocation.includes(NI_SI_ONSEN_ENTRY_MARKER));
    const liyanaTownDraftHit = isInLiuyuTownArea(currentWorldLocation) && (draftHasOnsen || chatHasOnsen);
    const liyanaTownStickyOn =
      liyanaTownDraftHit || stickyAfterDraftOff(liyanaStickyAnchor, LIYANA_STICKY_FLOOR_DELTA).on;
    const liyanaEnabledDesired = liyanaExactOnsen || liyanaTownStickyOn;

    const snapshot = `${heroInBattle}|${currentStyleLabel}|${currentWorldLocation}|${draftHasOnsen}|${chatHasOnsen}|${liyanaEnabledDesired}|${liyanaStickyAnchor}`;
    if (snapshot !== lastHeroSnapshot) scheduleSync();
  }, HERO_POLL_MS);

  // 保存避免重复启动
  (globalThis as any).__battleStyleHeroPollTimer = timer;
}

$(() => {
  errorCatched(() => {
    void syncWorldbookBattleStyle();

    eventOn(tavern_events.MESSAGE_RECEIVED, scheduleSync);
    eventOn(tavern_events.MESSAGE_SENT, scheduleSync);
    eventOn(tavern_events.MESSAGE_UPDATED, scheduleSync);
    eventOn(tavern_events.CHAT_CHANGED, scheduleSync);
    eventOn(tavern_events.CHARACTER_PAGE_LOADED, scheduleSync);

    // Dark 面板写入完成后可以派发这个事件（若存在）
    const scheduleSyncForDarkResync = () => scheduleSync();
    $(window).on('dark_worldbook_resync_needed', scheduleSyncForDarkResync);
    $(document).on('dark_worldbook_resync_needed', scheduleSyncForDarkResync);

    // 兜底轮询：捕捉“变量已变但事件未触发”
    if (!(globalThis as any).__battleStyleHeroPollTimer) startHeroPoll();

    bindTopSendTextareaForOnsen();
  })();
});

